import React, { Component } from 'react';
import { Link } from 'react-router-dom';

import getUrl from '../utils/https';

class ListItem extends Component {
  constructor() {
    super();

    this.state = {
      isLoading: true,
      data: []
    };
  }

  componentDidMount = () => {
    fetch(getUrl('item/' + this.props.id + '.json'))
      .then(response => response.json())
      .then(response => {
        this.setState({
          isLoading: false,
          data: response
        });
      });
  };

  render() {
    const date = new Date(this.state.data.time);
    return (
      <div className="title">
        {this.state.isLoading && 'Loading....'}
        {!this.state.isLoading && (
          <>
            <Link
              to={{
                state: { data: this.state.data },
                pathname: '/story/' + this.props.id
              }}
            >
              {this.state.data.title}
            </Link>
            <div className="details">
              <span>By: {this.state.data.by}</span>
              <span>Time: {date.toDateString()}</span>
              <span>
                <a href={this.state.data.url}>Visit Site</a>
              </span>
            </div>
          </>
        )}
      </div>
    );
  }
}

export default ListItem;
